# Sadə sinif və obyekt
class Car:
    def __init__(self, brand, model):
        self.brand = brand
        self.model = model

    def display_info(self):
        return f'{self.brand} {self.model}'

# Obyekt yaratmaq
my_car = Car('Toyota', 'Corolla')
print(my_car.display_info())

# Atributlar və metodlar
class Student:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def introduce(self):
        return f'Mən {self.name}, {self.age} yaşım var.'

student = Student('Ali', 20)
print(student.introduce())

# İrsiyyət
class Vehicle:
    def __init__(self, brand):
        self.brand = brand

    def start_engine(self):
        return f'{self.brand} mühərriki işə salındı.'

class Car(Vehicle):
    def __init__(self, brand, model):
        super().__init__(brand)
        self.model = model

    def display_info(self):
        return f'{self.brand} {self.model}'

car = Car('BMW', 'X5')
print(car.start_engine())
print(car.display_info())

# Polimorfizm
class Dog:
    def sound(self):
        return 'Hav-hav!'

class Cat:
    def sound(self):
        return 'Miyav!'

animals = [Dog(), Cat()]
for animal in animals:
    print(animal.sound())

# Inkapsulyasiya
class BankAccount:
    def __init__(self, owner, balance):
        self.owner = owner
        self.__balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.__balance += amount
            return f'{amount} əlavə edildi. Yeni balans: {self.__balance}'
        return 'Məbləğ müsbət olmalıdır!'

    def get_balance(self):
        return self.__balance

account = BankAccount('Ayşe', 1000)
print(account.deposit(500))
print(f'Balans: {account.get_balance()}')

# @property dekoratoru
class Person:
    def __init__(self, name):
        self._name = name

    @property
    def name(self):
        return self._name

    @name.setter
    def name(self, value):
        if value.strip():
            self._name = value
        else:
            print('Ad boş ola bilməz!')

person = Person('Veli')
print(person.name)
person.name = 'Zeynep'
print(person.name)
person.name = ''

# Statik və sinif metodları
class MathOperations:
    @staticmethod
    def add(a, b):
        return a + b

    @classmethod
    def multiply(cls, a, b):
        return a * b

print(MathOperations.add(3, 4))
print(MathOperations.multiply(3, 4))

